import math
from collections import Counter

class Solution(object):
    def minimumArrayLength(self, nums):
        min_val = min(nums)
        cnt = Counter(nums)

        # Case 1: any y in nums where y % min_val != 0
        # -> creates a value < min_val -> new minimum -> can eliminate everything -> length 1
        for v in cnt:
            if v % min_val != 0:
                return 1

        # Case 2: min_val appears once
        # -> can pair min_val with anything larger: min_val % larger = min_val (keeps it)
        # -> effectively eliminates all larger elements -> length 1
        if cnt[min_val] == 1:
            return 1

        # Case 3: all values divisible by min_val, min_val appears cnt times
        # -> can only reduce pairs of min_val (min_val % min_val = 0, but 0 is useless)
        # -> minimum achievable is ceil(cnt[min_val] / 2)
        return math.ceil(cnt[min_val] / 2)
